function hexWithAlpha(hex,alpha){const h=String(hex||'#ffffff').trim(); if(/^#([0-9a-f]{3}|[0-9a-f]{6})$/i.test(h)){let v=h.slice(1); if(v.length===3)v=v.split('').map(x=>x+x).join(''); const r=parseInt(v.slice(0,2),16),g=parseInt(v.slice(2,4),16),b=parseInt(v.slice(4,6),16); return `rgba(${r},${g},${b},${alpha})`; } return h;}
