  ids.forEach(name=>{const el=$('ap'+name); if(!el)return; el.addEventListener('input',()=>saveEditorAppearance()); el.addEventListener('change',()=>saveEditorAppearance()); const hex=$('ap'+name+'Hex'); if(hex){el.addEventListener('input',()=>{hex.value=el.value;}); hex.addEventListener('input',()=>{if(/^#[0-9a-fA-F]{6}$/.test(hex.value)){el.value=hex.value; saveEditorAppearance();}});}});
